const item = $input.first().json;

let telefoneDestinoAGR;

// Normaliza o nome do ponto de atendimento
const ponto = item['Ponto de Atendimento'] ? item['Ponto de Atendimento'].toLowerCase() : '';

// Define o telefone com base nos termos contidos no nome do ponto
if (ponto.includes('andromeda')) {
  telefoneDestinoAGR = '5512991665151'; // Rogério
} else if (ponto.includes('prado')) {
  telefoneDestinoAGR = '553197620119'; // Isabella
} else if (ponto.includes('mauá') || ponto.includes('maua')) {
  telefoneDestinoAGR = '5511996091624'; // Ingrid
} else {
  telefoneDestinoAGR = '5511983500019'; // Alexandre (default)
}

// Garante que o número esteja no formato E.164
telefoneDestinoAGR = telefoneDestinoAGR.replace(/\D/g, '');
if (!telefoneDestinoAGR.startsWith('55')) {
  telefoneDestinoAGR = '55' + telefoneDestinoAGR;
}

// Define o número no item para uso posterior
item.recipientPhoneNumber = telefoneDestinoAGR;

return [{ json: item }];

