const saida = $input.all().map(item => {
  const json = item.json;

  function normalizarTelefoneE164(telefone) {
    if (!telefone) return '';
    const digits = String(telefone).replace(/\D/g, '');
    if (/^55\d{10,11}$/.test(digits)) return digits;
    if (/^\d{10,11}$/.test(digits)) return '55' + digits;
    return '';
  }

  const cnpjLimpo = json.CNPJ ? String(json.CNPJ).replace(/\D/g, '') : '';
  const cpfLimpo = json.CPF ? String(json.CPF).replace(/\D/g, '') : '';

  let cpfMascarado = '';
  if (cpfLimpo.length === 11) {
    cpfMascarado = `${cpfLimpo.substring(0, 3)}.***.***-${cpfLimpo.substring(9, 11)}`;
  }

  const mapeamentoProdutos = {
    'e-CPF A1': ['e-cpf a1', 'ecpf a1', 'e cpf a1'],
    'e-CPF A3': ['e-cpf a3', 'ecpf a3', 'e cpf a3'],
    'e-CNPJ A1': ['e-cnpj a1', 'ecnpj a1', 'e cnpj a1'],
    'e-CNPJ A3': ['e-cnpj a3', 'ecnpj a3', 'e cnpj a3'],
    'e-Jurídico A3': ['jurídico', 'juridico'],
    'e-Saúde A3': ['saúde', 'saude'],
    'OM-eCPF': ['om-ecpf', 'om ecpf'],
  };

  const nomeProdutoOriginal = json.Produto || '';
  let produtoPadronizado = 'Não Identificado';
  for (const [nomePadrao, palavras] of Object.entries(mapeamentoProdutos)) {
    if (palavras.some(p => nomeProdutoOriginal.toLowerCase().includes(p))) {
      produtoPadronizado = nomePadrao;
      break;
    }
  }

  const tipoCertificado = cnpjLimpo ? 'CNPJ' : 'CPF';

  function toISO(dateAny) {
    if (!dateAny) return '';
    const s = String(dateAny).trim();
    if (/^\d{2}\/\d{2}\/\d{4}$/.test(s)) {
      const [dd, mm, yyyy] = s.split('/');
      return `${yyyy}-${mm}-${dd}`;
    }
    if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
    const p = new Date(s);
    if (!isNaN(p.getTime())) {
      const yyyy = p.getFullYear();
      const mm = String(p.getMonth() + 1).padStart(2, '0');
      const dd = String(p.getDate()).padStart(2, '0');
      return `${yyyy}-${mm}-${dd}`;
    }
    return '';
  }

  const vencimentoISO = toISO(json["Data de Vencimento"]);
  const telefoneE164 = normalizarTelefoneE164(json.Telefone);
  const primeiroNome = json.Cliente ? String(json.Cliente).split(' ')[0].toUpperCase() : '';

  return {
    json: {
      ...json,
      TelefoneNormalizado: telefoneE164,
      CNPJ: cnpjLimpo,
      CPF_Mascarado: cpfMascarado,
      ProdutoPadronizado: produtoPadronizado,
      PrimeiroNome: primeiroNome,
      TipoCertificado: tipoCertificado,
      UltimoContato: new Date().toISOString(),
      VencimentoISO: vencimentoISO,
    }
  };
});

return saida;

